DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `CalculateFinancialMetrics`()
BEGIN
    -- -------------------------------------------------------------------------
    -- 3.1. NỘI SUY DỮ LIỆU (IMPUTATION): Lợi nhuận gộp (20) = Doanh thu (10) - Giá vốn (11)
    -- Chỉ áp dụng cho Corporate (Mã Item 10, 11).
    -- -------------------------------------------------------------------------
    INSERT INTO Fact_Financials (Ticker, TimeKey, ItemID, Value_Current)
    SELECT src.Ticker, src.TimeKey, '20' AS ItemID, (src.Rev - src.COGS) AS Val
    FROM (
        SELECT 
            f1.Ticker, f1.TimeKey, 
            f1.Value_Current AS Rev, 
            IFNULL(f2.Value_Current, 0) AS COGS
        FROM Fact_Financials f1
        LEFT JOIN Fact_Financials f2 ON f1.Ticker = f2.Ticker AND f1.TimeKey = f2.TimeKey AND f2.ItemID = '11'
        WHERE f1.ItemID = '10'
    ) AS src
    ON DUPLICATE KEY UPDATE Value_Current = VALUES(Value_Current);

    -- -------------------------------------------------------------------------
    -- 3.2. TÍNH TOÁN CHỈ SỐ VÀ TĂNG TRƯỞNG (PEER COMPARISON LOGIC)
    -- Sử dụng CTE để Pivot dữ liệu từ dọc sang ngang trước khi tính toán
    -- -------------------------------------------------------------------------
    INSERT INTO Financial_Ratios (Ticker, TimeKey, ROA, ROE, Gross_Margin, Profit_Growth_QoQ, Asset_Growth_QoQ)
    SELECT 
        Ticker, 
        TimeKey,
        -- ROA = Lợi nhuận ST / Tổng tài sản (%)
        IFNULL(ROUND((NetProfit / NULLIF(TotalAssets, 0)) * 100, 4), 0) AS ROA,
        
        -- ROE = Lợi nhuận ST / Vốn chủ sở hữu (%)
        IFNULL(ROUND((NetProfit / NULLIF(Equity, 0)) * 100, 4), 0) AS ROE,
        
        -- Gross Margin = Lợi nhuận gộp / Doanh thu (%)
        IFNULL(ROUND((GrossProfit / NULLIF(NetRevenue, 0)) * 100, 4), 0) AS Gross_Margin,

        -- Tăng trưởng Lợi nhuận QoQ: (P_current - P_prev) / |P_prev|
        IFNULL(ROUND(((NetProfit - LAG(NetProfit) OVER(PARTITION BY Ticker ORDER BY TimeKey)) / 
               NULLIF(ABS(LAG(NetProfit) OVER(PARTITION BY Ticker ORDER BY TimeKey)), 0)) * 100, 4), 0) AS Profit_Growth_QoQ,

        -- Tăng trưởng Tài sản QoQ: (A_current - A_prev) / |A_prev|
        IFNULL(ROUND(((TotalAssets - LAG(TotalAssets) OVER(PARTITION BY Ticker ORDER BY TimeKey)) / 
               NULLIF(ABS(LAG(TotalAssets) OVER(PARTITION BY Ticker ORDER BY TimeKey)), 0)) * 100, 4), 0) AS Asset_Growth_QoQ

    FROM (
        -- Subquery bóc tách (Pivot) các mã ItemID quan trọng cho cả Bank và Corp
        SELECT 
            Ticker, 
            TimeKey,
            -- Lợi nhuận sau thuế (Dùng chung mã 60)
            MAX(CASE WHEN ItemID = '60' THEN Value_Current END) AS NetProfit,
            
            -- Doanh thu thuần (Dùng mã 10 cho Corp, mã BANK_IS_03 cho Bank)
            COALESCE(MAX(CASE WHEN ItemID = '10' THEN Value_Current END), 
                     MAX(CASE WHEN ItemID = 'BANK_IS_03' THEN Value_Current END)) AS NetRevenue,
            
            -- Lợi nhuận gộp (Mã 20 cho Corp, mã BANK_IS_03 cho Bank - lãi thuần là gộp của bank)
            COALESCE(MAX(CASE WHEN ItemID = '20' THEN Value_Current END), 
                     MAX(CASE WHEN ItemID = 'BANK_IS_03' THEN Value_Current END)) AS GrossProfit,
            
            -- Tổng tài sản (Mã 270 cho Corp, mã BANK_A0 cho Bank)
            COALESCE(MAX(CASE WHEN ItemID = '270' THEN Value_Current END), 
                     MAX(CASE WHEN ItemID = 'BANK_A0' THEN Value_Current END)) AS TotalAssets,
            
            -- Vốn chủ sở hữu (Mã 400/410 cho Corp, mã BANK_VIII_EQUITY cho Bank)
            COALESCE(MAX(CASE WHEN ItemID = '400' THEN Value_Current END), 
                     MAX(CASE WHEN ItemID = '410' THEN Value_Current END),
                     MAX(CASE WHEN ItemID = 'BANK_VIII_EQUITY' THEN Value_Current END)) AS Equity
                     
        FROM Fact_Financials
        GROUP BY Ticker, TimeKey
    ) AS WideTable
    ON DUPLICATE KEY UPDATE 
        ROA = VALUES(ROA), 
        ROE = VALUES(ROE), 
        Gross_Margin = VALUES(Gross_Margin),
        Profit_Growth_QoQ = VALUES(Profit_Growth_QoQ),
        Asset_Growth_QoQ = VALUES(Asset_Growth_QoQ);

END ;;
